```class Solution {
public:
    int countCharacters(vector<string>& words, string chars) {
        int result = 0;
        for (string word : words) {
            result += countCharactersHelper(word, chars);
        }
        return result;
    }

    int countCharactersHelper(string word, string chars) {
        int count = 0;
        for (char c : word) {
            if (containsChar(c, chars)) {
                count++;
            }
        }
        return count;
    }

    bool containsChar(char c, string chars) {
        for (char ch : chars) {
            if (c == ch) {
                return true;
            }
        }
        return false;
    }
};
```

